import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import PrivacyNote from "@/components/PrivacyNote";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FormulaBlock from "@/components/FormulaBlock";
import GlossarySection from "@/components/GlossarySection";
import SourceCitations from "@/components/SourceCitations";
import FAQItem from "@/components/FAQItem";

const UNIT_PREFERENCE_KEY = "calchive-unit-system";

const BMI_CATEGORIES = [
  { label: "Underweight", range: "< 18.5", max: 18.5, color: "bg-blue-100 dark:bg-blue-950/40 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-800" },
  { label: "Normal weight", range: "18.5 - 24.9", max: 25, color: "bg-emerald-100 dark:bg-emerald-950/40 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800" },
  { label: "Overweight", range: "25 - 29.9", max: 30, color: "bg-amber-100 dark:bg-amber-950/40 text-amber-600 dark:text-amber-400 border-amber-200 dark:border-amber-800" },
  { label: "Obese Class I", range: "30 - 34.9", max: 35, color: "bg-orange-100 dark:bg-orange-950/40 text-orange-600 dark:text-orange-400 border-orange-200 dark:border-orange-800" },
  { label: "Obese Class II", range: "35 - 39.9", max: 40, color: "bg-red-100 dark:bg-red-950/40 text-red-600 dark:text-red-400 border-red-200 dark:border-red-800" },
  { label: "Obese Class III", range: "40+", max: Infinity, color: "bg-rose-100 dark:bg-rose-950/40 text-rose-600 dark:text-rose-400 border-rose-200 dark:border-rose-800" },
];

const FAQS = [
  { q: "What is BMI?", a: "BMI (Body Mass Index) is a measure of body fat based on height and weight. It's calculated as weight (kg) / height (m)- BMI is used as a screening tool for weight categories that may lead to health problems." },
  { q: "What are the BMI categories?", a: "Underweight: below 18.5. Normal weight: 18.5-24.9. Overweight: 25-29.9. Obese Class I: 30-34.9. Obese Class II: 35-39.9. Obese Class III: 40 and above." },
  { q: "Is BMI always accurate?", a: "BMI has limitations - it doesn't distinguish between muscle and fat mass. Athletes often have high BMIs due to muscle. It also doesn't account for fat distribution, age, sex, or ethnicity differences in body composition." },
  { q: "What is a healthy BMI range?", a: "A BMI between 18.5 and 24.9 is considered healthy by the World Health Organization. However, ideal BMI can vary by age and ethnicity. Asian populations may have health risks at lower BMI thresholds." },
  { q: "What BMI is considered obese?", a: "A BMI of 30 or higher is classified as obese. Obesity is further divided into Class I (30-34.9), Class II (35-39.9), and Class III, also called 'severe' or 'morbid' obesity (40+). Each class carries increasing health risks." },
  { q: "How do I lower my BMI?", a: "BMI decreases when weight decreases. A combination of a caloric deficit diet (eating less than you burn), regular aerobic exercise (150+ minutes/week), and strength training is the most effective approach. Losing 1-2 lbs per week is considered safe and sustainable." },
  { q: "Does BMI differ for men and women?", a: "The BMI formula is the same for men and women, but body composition differs - women naturally have more fat relative to muscle at the same BMI. Some researchers argue for sex-specific thresholds, but the WHO categories remain the standard clinical reference." },
];

function getSavedUnitPreference() {
  if (typeof window === "undefined") return "imperial";
  return localStorage.getItem(UNIT_PREFERENCE_KEY) === "metric" ? "metric" : "imperial";
}

function roundTo(value: number, places = 1) {
  const factor = 10 ** places;
  return Math.round(value * factor) / factor;
}

export default function BMICalculator() {
  const [unit, setUnit] = useState<"imperial" | "metric">(getSavedUnitPreference);
  const [heightFt, setHeightFt] = useState(5);
  const [heightIn, setHeightIn] = useState(9);
  const [heightCm, setHeightCm] = useState(175);
  const [weightLbs, setWeightLbs] = useState(160);
  const [weightKg, setWeightKg] = useState(70);

  const bmi = unit === "imperial"
    ? (weightLbs / Math.pow(heightFt * 12 + heightIn, 2)) * 703
    : weightKg / Math.pow(heightCm / 100, 2);

  const catIdx = BMI_CATEGORIES.findIndex(c => bmi < c.max);
  const categoryIndex = catIdx === -1 ? BMI_CATEGORIES.length - 1 : catIdx;
  const category = BMI_CATEGORIES[categoryIndex];
  const gradients = ["from-blue-500 to-blue-700", "from-emerald-500 to-emerald-700", "from-amber-500 to-amber-700", "from-orange-500 to-orange-700", "from-red-500 to-red-700", "from-rose-500 to-rose-700"];
  const gradient = gradients[categoryIndex];

  const switchUnit = (nextUnit: "imperial" | "metric") => {
    if (nextUnit === unit) return;

    if (nextUnit === "metric") {
      const totalInches = heightFt * 12 + heightIn;
      setHeightCm(roundTo(totalInches * 2.54));
      setWeightKg(roundTo(weightLbs * 0.453592));
    } else {
      const totalInches = heightCm / 2.54;
      setHeightFt(Math.floor(totalInches / 12));
      setHeightIn(roundTo(totalInches % 12));
      setWeightLbs(roundTo(weightKg / 0.453592));
    }

    setUnit(nextUnit);
    localStorage.setItem(UNIT_PREFERENCE_KEY, nextUnit);
  };

  return (
    <>
      <SEOHead
        title="Free BMI Calculator Online - Calculate Body Mass Index Instantly | CalcHive"
        description="Free online BMI calculator. Calculate your Body Mass Index and see your weight category instantly. 100% free for everyone, no signup required, works on all devices."
        canonical="/bmi-calculator"
        keywords="free BMI calculator, body mass index calculator free online, calculate BMI free, free BMI checker, BMI calculator no signup"
        category="Health Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free BMI Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free BMI calculator to calculate BMI free and check your Body Mass Index instantly. This body mass index calculator free online works as a free BMI checker and BMI calculator no signup tool on mobile and desktop.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-6">
          <div className="flex gap-2 mb-6">
            {(["imperial", "metric"] as const).map(u => (
              <button key={u} onClick={() => switchUnit(u)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border capitalize transition-all ${unit === u ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{u}</button>
            ))}
          </div>
          <div className="space-y-6 mb-8">
            {unit === "imperial" ? (
              <>
                <SliderInput id="height-ft" label="Height (feet)" value={heightFt} min={3} max={8} step={1} onChange={setHeightFt} format={v => `${v} ft`} testId="input-height-ft" />
                <SliderInput id="height-in" label="Height (inches)" value={heightIn} min={0} max={11} step={0.1} onChange={setHeightIn} format={v => `${v} in`} testId="input-height-in" />
                <SliderInput id="weight-lbs" label="Weight (lbs)" value={weightLbs} min={66} max={1400} step={0.1} onChange={setWeightLbs} format={v => `${v} lbs`} testId="input-weight" />
              </>
            ) : (
              <>
                <SliderInput id="height-cm" label="Height (cm)" value={heightCm} min={91.44} max={243.84} step={0.1} onChange={setHeightCm} format={v => `${v} cm`} testId="input-height-cm" />
                <SliderInput id="weight-kg" label="Weight (kg)" value={weightKg} min={30} max={635} step={0.1} onChange={setWeightKg} format={v => `${v} kg`} testId="input-weight-kg" />
              </>
            )}
          </div>
          <PrivacyNote />
          <motion.div key={`${unit}-${heightFt}-${heightIn}-${heightCm}-${weightLbs}-${weightKg}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${gradient} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Your BMI</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-bmi">{bmi.toFixed(1)}</p>
              <p className="text-white/70 text-sm mt-1">{category.label}</p>
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              {BMI_CATEGORIES.map((c, i) => (
                <div key={c.label} className={`rounded-xl p-3 text-center border ${i === categoryIndex ? c.color + " ring-2 ring-current" : "bg-muted/40 text-muted-foreground border-border"}`}>
                  <p className="text-xs font-bold">{c.range}</p>
                  <p className="text-xs opacity-80 mt-0.5">{c.label}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <MedicalDisclaimer /><ShareButton />

        <FormulaBlock
          formula={[
            "Metric: BMI = Weight (kg) / Height (m)^2",
            "Imperial: BMI = (Weight (lbs) / Height (in)^2) x 703",
          ]}
          legend="Where height in meters = height_cm / 100. The 703 constant converts lbs/in^2 to the metric kg/m^2 scale."
          source="World Health Organization (WHO) BMI Classification"
          sourceHref="https://www.who.int/news-room/fact-sheets/detail/obesity-and-overweight"
          collapsible
        />

        <section className="ec-article-section mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your BMI for Free</h2>
          <p className="text-muted-foreground leading-relaxed">BMI divides weight by the square of height. The formula differs slightly between metric and imperial units, but both produce the same BMI score for the same person.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-2">
            <p className="font-semibold text-muted-foreground text-xs uppercase tracking-widest mb-1">Metric</p>
            <p>BMI = Weight (kg) / Height (m)^2</p>
            <p className="font-semibold text-muted-foreground text-xs uppercase tracking-widest mt-3 mb-1">Imperial</p>
            <p>BMI = (Weight (lbs) / Height (in)^2) x 703</p>
          </div>
          <p className="text-muted-foreground leading-relaxed">Example: A person who is 5 ft 9 in (175 cm) and weighs 160 lbs (72.6 kg): BMI = (160 / 69^2) x 703 = 23.6 - Normal weight.</p>

          <h2 className="text-2xl font-bold text-foreground">What Does Your BMI Score Mean</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["BMI Range", "Category", "Health Risk", "Action"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Below 18.5", "Underweight", "Moderate", "Increase caloric intake; see a doctor if severe"],
                  ["18.5 - 24.9", "Normal weight", "Minimal", "Maintain through balanced diet and exercise"],
                  ["25.0 - 29.9", "Overweight", "Increased", "Lifestyle changes recommended"],
                  ["30.0 - 34.9", "Obese Class I", "High", "Medical consultation recommended"],
                  ["35.0 - 39.9", "Obese Class II", "Very High", "Medical intervention often needed"],
                  ["40.0+", "Obese Class III", "Extremely High", "Medical treatment required"],
                ].map(([range, cat, risk, action]) => (
                  <tr key={range} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{range}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cat}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{risk}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{action}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Body Mass Index Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Height", "Underweight (< 18.5)", "Normal (18.5-24.9)", "Overweight (25-29.9)"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["5'4\" (163 cm)", "Under 108 lbs", "108-145 lbs", "146-174 lbs"],
                  ["5'6\" (168 cm)", "Under 115 lbs", "115-154 lbs", "155-185 lbs"],
                  ["5'9\" (175 cm)", "Under 125 lbs", "125-168 lbs", "169-202 lbs"],
                  ["5'11\" (180 cm)", "Under 133 lbs", "133-178 lbs", "179-214 lbs"],
                  ["6'2\" (188 cm)", "Under 145 lbs", "145-194 lbs", "195-233 lbs"],
                ].map(([height, ...cells]) => (
                  <tr key={height} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{height}</td>
                    {cells.map((c, i) => <td key={i} className="py-2.5 px-4 text-muted-foreground">{c}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h3 className="text-2xl font-bold text-foreground">Limitations of BMI</h3>
          <ul className="space-y-2 text-muted-foreground list-disc list-inside">
            <li>BMI does not distinguish between muscle and fat - bodybuilders often register as "overweight" or "obese."</li>
            <li>BMI doesn't indicate fat distribution. Visceral fat (around organs) is more dangerous than subcutaneous fat, but BMI doesn't measure either location.</li>
            <li>Age and sex affect body composition independently of BMI - elderly individuals often have more fat at lower BMI values.</li>
            <li>Some ethnic groups (particularly South and East Asian populations) face increased health risks at BMI values below the standard "overweight" threshold of 25.</li>
            <li>For a more complete picture, use BMI alongside waist circumference, body fat percentage, and other health markers.</li>
          </ul>
        </section>

        <GlossarySection headingLevel="h3" terms={[
          { term: "BMI (Body Mass Index)", definition: "A numerical measure of body weight relative to height, used as a screening tool for weight categories. It does not directly measure body fat percentage." },
          { term: "Normal Weight Range", definition: "A BMI of 18.5-24.9 as defined by the WHO. People in this range typically have the lowest risk of weight-related health conditions." },
          { term: "Overweight", definition: "A BMI of 25-29.9. Indicates excess weight relative to height, with moderately increased risk of type 2 diabetes, hypertension, and cardiovascular disease." },
          { term: "Obese", definition: "A BMI of 30 or above. Subdivided into Class I (30-34.9), Class II (35-39.9), and Class III (40+), each carrying progressively higher health risks." },
          { term: "703 Conversion Factor", definition: "The constant used when calculating BMI from imperial units (lbs/in- It converts pounds per square inch to the metric kg/m- scale so results match the WHO classification system." },
        ]} />

        <SourceCitations headingLevel="h3" citations={[
          { label: "WHO - Obesity and Overweight Fact Sheet", href: "https://www.who.int/news-room/fact-sheets/detail/obesity-and-overweight", note: "Official WHO BMI classification and health guidelines" },
          { label: "CDC - About Adult BMI", href: "https://www.cdc.gov/bmi/adult-calculator/bmi-for-adults.html", note: "U.S. Centers for Disease Control BMI reference" },
          { label: "NIH NHLBI - Calculate Your Body Mass Index", href: "https://www.nhlbi.nih.gov/health/educational/lose_wt/BMI/bmi-m.htm", note: "National Heart, Lung, and Blood Institute reference" },
        ]} />

        <section className="mb-8 mt-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/bmi-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


